import{_ as t,o as d,c as a,ae as o}from"./chunks/framework.DTwQaIIa.js";const p=JSON.parse('{"title":"Commands & Permissions","description":"","frontmatter":{},"headers":[],"relativePath":"en/modules/strengthen/commands.md","filePath":"en/modules/strengthen/commands.md"}'),n={name:"en/modules/strengthen/commands.md"};function r(s,e,c,i,l,m){return d(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="commands-permissions" tabindex="-1">Commands &amp; Permissions <a class="header-anchor" href="#commands-permissions" aria-label="Permalink to &quot;Commands &amp; Permissions&quot;">​</a></h1><p>All EmakiStrengthen commands are accessed through the root command <code>/emakistrengthen</code> (alias <code>/estrengthen</code>).</p><h2 id="command-list" tabindex="-1">Command List <a class="header-anchor" href="#command-list" aria-label="Permalink to &quot;Command List&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Command</th><th>Parameters</th><th>Description</th><th>Permission</th></tr></thead><tbody><tr><td><code>/estrengthen help</code></td><td>—</td><td>Display help information</td><td>None</td></tr><tr><td><code>/estrengthen open</code></td><td><code>[recipeID]</code></td><td>Open the enhancement GUI (optionally specify a recipe)</td><td><code>emakistrengthen.use</code></td></tr><tr><td><code>/estrengthen reload</code></td><td>—</td><td>Reload all configuration and resource files</td><td><code>emakistrengthen.reload</code></td></tr><tr><td><code>/estrengthen inspect</code></td><td><code>&lt;player&gt;</code></td><td>View the enhancement status of a player&#39;s held equipment</td><td><code>emakistrengthen.admin</code></td></tr><tr><td><code>/estrengthen refresh</code></td><td><code>&lt;player&gt;</code></td><td>Refresh the enhancement layer display for all equipment in a player&#39;s inventory</td><td><code>emakistrengthen.admin</code></td></tr><tr><td><code>/estrengthen setstar</code></td><td><code>&lt;player&gt; &lt;star&gt;</code></td><td>Set the star level of a player&#39;s held equipment</td><td><code>emakistrengthen.admin</code></td></tr><tr><td><code>/estrengthen clearstate</code></td><td><code>&lt;player&gt;</code></td><td>Clear all enhancement data from a player&#39;s held equipment</td><td><code>emakistrengthen.admin</code></td></tr><tr><td><code>/estrengthen clearcrack</code></td><td><code>&lt;player&gt;</code></td><td>Clear the crack state from a player&#39;s held equipment</td><td><code>emakistrengthen.admin</code></td></tr><tr><td><code>/estrengthen givecatalyst</code></td><td><code>&lt;player&gt; &lt;catalystID&gt; [amount]</code></td><td>Give a player enhancement catalyst items</td><td><code>emakistrengthen.admin</code></td></tr></tbody></table><h3 id="command-details" tabindex="-1">Command Details <a class="header-anchor" href="#command-details" aria-label="Permalink to &quot;Command Details&quot;">​</a></h3><p><strong><code>/estrengthen open [recipeID]</code></strong></p><p>Opens the enhancement GUI. If a recipe ID is specified, that recipe is used directly; otherwise, the recipe is automatically matched after placing equipment.</p><p><strong><code>/estrengthen reload</code></strong></p><p>Reloads the following resources:</p><ul><li><code>config.yml</code> main configuration</li><li><code>lang/</code> language files</li><li><code>gui/</code> GUI configuration</li><li><code>recipes/</code> recipe files</li></ul><p><strong><code>/estrengthen inspect &lt;player&gt;</code></strong></p><p>Views detailed enhancement information for the specified player&#39;s held equipment, including:</p><ul><li>Current star level</li><li>Temper level</li><li>Crack level</li><li>Cumulative success/failure count</li><li>Recipe ID used</li><li>Last enhancement time</li></ul><p><strong><code>/estrengthen setstar &lt;player&gt; &lt;star&gt;</code></strong></p><p>Directly sets the equipment&#39;s star level. This command will:</p><ul><li>Update <code>current_star</code> in PDC</li><li>Rebuild structured_presentation based on the target star level</li><li>Re-write the stats and attributes for the corresponding star level</li><li>Reset temper level to 0</li></ul><p><strong><code>/estrengthen clearstate &lt;player&gt;</code></strong></p><p>Completely clears all enhancement data from the equipment, including star level, temper, crack, audit records, etc. The equipment will be restored to its un-enhanced state.</p><div class="warning custom-block"><p class="custom-block-title">Note</p><p>The <code>clearstate</code> operation is irreversible. Please confirm the target is correct before executing.</p></div><p><strong><code>/estrengthen clearcrack &lt;player&gt;</code></strong></p><p>Only clears the equipment&#39;s crack state (<code>crack_level</code> reset to 0) without affecting star level or other data.</p><p><strong><code>/estrengthen givecatalyst &lt;player&gt; &lt;catalystID&gt; [amount]</code></strong></p><p>Gives the player the specified enhancement catalyst item. Catalysts can be enhancement stones, protection items, etc. The default amount is 1.</p><h2 id="permission-nodes" tabindex="-1">Permission Nodes <a class="header-anchor" href="#permission-nodes" aria-label="Permalink to &quot;Permission Nodes&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Permission Node</th><th>Description</th><th>Default</th></tr></thead><tbody><tr><td><code>emakistrengthen.use</code></td><td>Allow use of enhancement features</td><td><code>true</code></td></tr><tr><td><code>emakistrengthen.reload</code></td><td>Allow configuration reload</td><td><code>op</code></td></tr><tr><td><code>emakistrengthen.admin</code></td><td>Admin permission (includes inspect, refresh, setstar, clearstate, clearcrack, givecatalyst)</td><td><code>op</code></td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">Tip</p><p>The <code>emakistrengthen.admin</code> permission includes access to all admin commands. For more granular permission control, you can configure individual sub-commands through a permissions plugin (such as LuckPerms).</p></div>',26)])])}const g=t(n,[["render",r]]);export{p as __pageData,g as default};
